"use client";

import { useState, useEffect, useRef, useCallback, memo } from "react";
import { useAppStore } from "@/lib/store";
import { useThrottle } from "@/hooks/use-debounce";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import {
  Wallet,
  Gamepad2,
  ArrowUpDown,
  CreditCard,
  RefreshCw,
  XIcon,
  RotateCcw,
  Undo2,
  Clock,
  Pause,
} from "lucide-react";
import Link from "next/link";
import Image from "next/image";

// Icon data
const ICONS = [
  { id: "umbrella", name: "Umbrella", image: "/umbrella.webp" },
  { id: "football", name: "Football", image: "/football.webp" },
  { id: "dice", name: "Dice", image: "/dice.webp" },
  { id: "bell", name: "Bell", image: "/bell.webp" },
  { id: "star", name: "Star", image: "/star.webp" },
  { id: "heart", name: "Heart", image: "/heart.webp" },
  { id: "moon", name: "Moon", image: "/moon.webp" },
  { id: "sun", name: "Sun", image: "/sun.webp" },
  { id: "diamond", name: "Diamond", image: "/diamond.webp" },
  { id: "crown", name: "Crown", image: "/crown.webp" },
  { id: "lightning", name: "Lightning", image: "/lightning.webp" },
  { id: "spinning-top", name: "Spinning Top", image: "/spinning-top.webp" },
  { id: "rose", name: "Rose", image: "/rose.webp" },
  { id: "butterfly", name: "Butterfly", image: "/butterfly.webp" },
  { id: "sparrow", name: "Sparrow", image: "/sparrow.webp" },
  { id: "rabbit", name: "Rabbit", image: "/rabbit.webp" },
];

const CHIP_VALUES = [10, 20, 50, 100, 200, 500];

// Preload images to prevent loading delays
const preloadImages = () => {
  ICONS.forEach(icon => {
    const img = new window.Image()
    img.src = icon.image
  })
}

// Memoized Icon Component
const IconButton = memo(({ 
  id, 
  name, 
  image, 
  onClick, 
  disabled, 
  localBetAmount, 
  confirmedBetAmount, 
  totalBetAmount, 
  hasMyBet,
  timeRemaining 
}: {
  id: string;
  name: string;
  image: string;
  onClick: () => void;
  disabled: boolean;
  localBetAmount: number;
  confirmedBetAmount: number;
  totalBetAmount: number;
  hasMyBet: boolean;
  timeRemaining: string;
}) => {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={`relative flex flex-col items-center justify-center p-2 lg:p-3 xl:p-4 2xl:p-5 rounded-lg border transition-all aspect-square ${
        hasMyBet
          ? "bg-green-600/30 border-green-500"
          : "bg-slate-700/50 border-slate-600 hover:border-slate-500"
      } ${
        timeRemaining === "Slot Closed" 
          ? "opacity-50 cursor-not-allowed" 
          : "hover:border-slate-500 cursor-pointer"
      }`}
    >
      {(localBetAmount > 0 || confirmedBetAmount > 0) && (
        <>
          <div className="absolute -top-0.5 -right-0.5 lg:-top-1 lg:-right-1 xl:-top-1.5 xl:-right-1.5 2xl:-top-2 2xl:-right-2 bg-green-600 text-white text-[8px] lg:text-[9px] xl:text-[10px] 2xl:text-xs font-bold rounded-full w-3 h-3 lg:w-4 lg:h-4 xl:w-5 xl:h-5 2xl:w-6 2xl:h-6 flex items-center justify-center border-2 border-white shadow-lg z-10">
            {totalBetAmount}
          </div>
          <div className="absolute top-1 left-1 bg-green-600 text-white text-[7px] lg:text-[8px] xl:text-[9px] 2xl:text-[10px] px-1.5 lg:px-2 xl:px-2.5 2xl:px-3 py-0.5 lg:py-1 xl:py-1.5 2xl:py-2 rounded-full font-semibold shadow-lg z-10">
            BETTED
          </div>
        </>
      )}
      
      <Image
        src={image}
        alt={name}
        width={64}
        height={64}
        className="w-16 h-16 lg:w-20 lg:h-20 xl:w-24 xl:h-24 2xl:w-28 2xl:h-28 object-contain"
        priority={id === 'umbrella' || id === 'football'}
      />
      
      <span className="text-[9px] lg:text-[10px] xl:text-sm 2xl:text-base text-slate-300 mt-1 lg:mt-1 xl:mt-1.5 2xl:mt-2 text-center leading-tight">
        {name}
      </span>
    </button>
  );
});

// Animated Clock Component
const AnimatedClock = ({ size = 24, className = "" }: { size?: number; className?: string }) => {
  return (
    <div className={`relative ${className}`} style={{ width: size, height: size }}>
      <div 
        className="absolute inset-0 rounded-full border-2 border-blue-400"
        style={{
          animation: 'spin 2s linear infinite',
        }}
      />
      <div className="absolute inset-1 rounded-full border-2 border-blue-300" />
      <div className="absolute inset-2 rounded-full border border-blue-200" />
      <div className="absolute inset-0 flex items-center justify-center">
        <Clock size={size * 0.4} className="text-blue-400" />
      </div>
      <style jsx>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default function Dashboard() {
  const { user } = useAppStore();
  const [currentSlot, setCurrentSlot] = useState<any>(null);
  const [selectedIcon, setSelectedIcon] = useState<string>("");
  const [selectedChip, setSelectedChip] = useState<number>(20);
  const [placedBets, setPlacedBets] = useState<
    { icon: string; amount: number }[]
  >([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [timeRemaining, setTimeRemaining] = useState<string>("");
  const [slotLoading, setSlotLoading] = useState(true);

  // Preload images on mount
  useEffect(() => {
    preloadImages()
    loadCurrentSlot()
  }, [])

  const loadCurrentSlot = async () => {
    try {
      const response = await fetch('/api/prediction-slots?current=true')
      const data = await response.json()
      if (data.success && data.data) {
        setCurrentSlot(data.data)
      }
    } catch (error) {
      console.error('Failed to load current slot:', error)
    } finally {
      setSlotLoading(false)
    }
  }

  const handleIconClick = useCallback((iconId: string) => {
    if (!currentSlot) {
      setError("No active slot found");
      return;
    }

    const now = Date.now();
    const end = new Date(currentSlot.endTime).getTime();
    if (now >= end) {
      setError("Slot has ended. Bets are no longer accepted.");
      return;
    }

    if (selectedChip < 10 || selectedChip > 500) {
      setError("Invalid bet amount selected.");
      return;
    }

    if (!user || user.walletBalance < selectedChip) {
      setError("Insufficient coins in wallet");
      return;
    }

    setPlacedBets((prev) => {
      const existingBetIndex = prev.findIndex((bet) => bet.icon === iconId);
      if (existingBetIndex !== -1) {
        const updatedBets = [...prev];
        updatedBets[existingBetIndex] = {
          ...updatedBets[existingBetIndex],
          amount: updatedBets[existingBetIndex].amount + selectedChip,
        };
        return updatedBets;
      } else {
        return [...prev, { icon: iconId, amount: selectedChip }];
      }
    });
  }, [currentSlot, selectedChip, user]);

  const handleSubmitBets = async () => {
    if (placedBets.length === 0) {
      setError("Please place at least one bet");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const response = await fetch('/api/bets', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
        body: JSON.stringify({
          slotId: currentSlot.id,
          bets: placedBets,
        }),
      });

      const data = await response.json();
      if (data.success) {
        setPlacedBets([]);
        setError("Bets placed successfully!");
        setTimeout(() => setError(""), 3000);
      } else {
        setError(data.error || "Failed to place bets");
      }
    } catch (error) {
      setError("Failed to place bets. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const getTotalBetAmount = () => {
    return placedBets.reduce((total, bet) => total + bet.amount, 0);
  };

  const getBetAmountForIcon = (iconId: string) => {
    const bet = placedBets.find((bet) => bet.icon === iconId);
    return bet ? bet.amount : 0;
  };

  // Quick Actions
  const quickActions = [
    {
      href: "/dashboard/wallet",
      label: "Wallet",
      icon: Wallet,
      description: "Manage your wallet",
      color: "text-green-400",
    },
    {
      href: "/dashboard/transactions",
      label: "Transactions",
      icon: ArrowUpDown,
      description: "View transaction history",
      color: "text-blue-400",
    },
    {
      href: "/dashboard/withdrawals",
      label: "Withdrawals",
      icon: CreditCard,
      description: "Request withdrawals",
      color: "text-purple-400",
    },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 pb-6">
      {/* Header */}
      <div className="sticky top-0 z-50 bg-gradient-to-r from-slate-900 to-slate-800 border-b border-slate-700 px-3 py-2">
        <div className="flex justify-between items-center max-w-5xl mx-auto">
          <div className="flex items-center gap-4">
            <div>
              <p className="text-[10px] text-slate-400">Balance</p>
              <p className="text-base font-bold text-green-400">
                ₹{user?.walletBalance?.toFixed(2) || "0.00"}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <p className="text-[10px] text-slate-400">Current Slot</p>
            {slotLoading ? (
              <div className="w-4 h-4 border-2 border-slate-600 border-t-transparent animate-spin rounded-full" />
            ) : currentSlot ? (
              <div className="text-sm font-semibold text-white">
                {timeRemaining || "Loading..."}
              </div>
            ) : (
              <div className="text-sm text-slate-400">No active slot</div>
            )}
          </div>
        </div>
      </div>

      <div className="max-w-5xl mx-auto px-3 py-4">
        {/* Error Message */}
        {error && (
          <div className="mb-4 p-3 bg-red-600/20 border border-red-500 rounded-lg">
            <p className="text-red-400 text-sm">{error}</p>
          </div>
        )}

        {/* Betting Interface */}
        <Card className="border-slate-700 bg-slate-800 mb-4">
          <CardHeader>
            <CardTitle className="text-white">Place Your Bets</CardTitle>
            <CardDescription className="text-slate-400">
              Select icons and place your bets before the slot closes
            </CardDescription>
          </CardHeader>
          <CardContent>
            {/* Timer */}
            <div className="flex justify-center mb-4">
              {timeRemaining === "Slot Closed" ? (
                <div className="flex items-center gap-2 text-red-400">
                  <AnimatedClock size={20} />
                  <span className="text-sm font-semibold">Slot Closed</span>
                </div>
              ) : (
                <div className="text-center">
                  <p className="text-xs text-slate-400 mb-1">Time Remaining</p>
                  <p className="text-2xl font-bold text-white">{timeRemaining}</p>
                </div>
              )}
            </div>

            {/* Icon Grid */}
            <div className="grid grid-cols-4 gap-2 lg:gap-3 xl:gap-4 mb-4">
              {ICONS.map(({ id, name, image }) => {
                const localBetAmount = getBetAmountForIcon(id);
                const hasMyBet = localBetAmount > 0;
                const totalBetAmount = localBetAmount;

                return (
                  <IconButton
                    key={id}
                    id={id}
                    name={name}
                    image={image}
                    onClick={() => handleIconClick(id)}
                    disabled={timeRemaining === "Slot Closed"}
                    localBetAmount={localBetAmount}
                    confirmedBetAmount={0}
                    totalBetAmount={totalBetAmount}
                    hasMyBet={hasMyBet}
                    timeRemaining={timeRemaining}
                  />
                );
              })}
            </div>

            {/* Chip Selection */}
            <div className="mb-4">
              <p className="text-sm text-slate-400 mb-2">Select Bet Amount:</p>
              <div className="flex flex-wrap gap-2">
                {CHIP_VALUES.map((chip) => (
                  <button
                    key={chip}
                    onClick={() => setSelectedChip(chip)}
                    className={`px-3 py-2 rounded-lg font-semibold transition-all ${
                      selectedChip === chip
                        ? "bg-blue-600 text-white"
                        : "bg-slate-700 text-slate-300 hover:bg-slate-600"
                    }`}
                  >
                    ₹{chip}
                  </button>
                ))}
              </div>
            </div>

            {/* Placed Bets */}
            {placedBets.length > 0 && (
              <div className="mb-4">
                <div className="flex justify-between items-center mb-2">
                  <p className="text-sm text-slate-400">Your Bets:</p>
                  <p className="text-sm font-semibold text-white">
                    Total: ₹{getTotalBetAmount().toFixed(2)}
                  </p>
                </div>
                <div className="flex flex-wrap gap-2">
                  {placedBets.map((bet, index) => (
                    <div
                      key={index}
                      className="bg-slate-700 px-2 py-1 rounded text-xs text-slate-300"
                    >
                      {ICONS.find(icon => icon.id === bet.icon)?.name}: ₹{bet.amount}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Submit Button */}
            <Button
              onClick={handleSubmitBets}
              disabled={loading || placedBets.length === 0 || timeRemaining === "Slot Closed"}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3"
            >
              {loading ? "Placing Bets..." : "Confirm Bets"}
            </Button>
          </CardContent>
        </Card>

        {/* Quick Actions */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          {quickActions.map((action) => {
            const Icon = action.icon;
            return (
              <Link key={action.href} href={action.href}>
                <Card className="border-slate-700 bg-slate-800 hover:bg-slate-750 transition-colors cursor-pointer h-full">
                  <CardContent className="p-4">
                    <div className="flex items-center gap-3">
                      <Icon className={`w-6 h-6 ${action.color}`} />
                      <div>
                        <h3 className="font-semibold text-white text-sm">
                          {action.label}
                        </h3>
                        <p className="text-xs text-slate-400">
                          {action.description}
                        </p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </Link>
            );
          })}
        </div>
      </div>
    </div>
  );
}
